class Solution(object):
    def minDeletionSize(self, strs):
        n, m = len(strs), len(strs[0])
        deletions = 0
        is_sorted = [False] * n
        for col in range(m):
            new_is_sorted = is_sorted[:]
            for row in range(n - 1):
                if not is_sorted[row]:
                    if strs[row][col] > strs[row + 1][col]:
                        deletions += 1
                        break
                    elif strs[row][col] < strs[row + 1][col]:
                        new_is_sorted[row] = True
            else:
                is_sorted = new_is_sorted
        return deletions
